begin;
create table if not exists public.dns_records(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),project_id uuid references public.projects(id),client_id uuid references public.clients(id),domain_id uuid references public.domains(id) on delete cascade,record_type text not null check(record_type in('A','AAAA','CNAME','MX','TXT','SPF','DKIM','DMARC','SRV','NS')),name text not null,value text not null,ttl integer check(ttl>0),purpose text,status public.health_status not null default 'unverified',changed_at timestamptz,created_by uuid references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.ssl_certificates(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),project_id uuid references public.projects(id),client_id uuid references public.clients(id),domain_id uuid references public.domains(id) on delete cascade,issuer text,issued_at date,expires_at date,auto_renew boolean not null default false,status public.health_status not null default 'unverified',last_checked_at timestamptz,created_by uuid references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.email_services(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),project_id uuid references public.projects(id),client_id uuid references public.clients(id),domain_id uuid references public.domains(id) on delete cascade,provider text,imap_server text,smtp_server text,webmail_url text,spf text,dkim text,dmarc text,status public.health_status not null default 'unverified',created_by uuid references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create index if not exists dns_domain on public.dns_records(domain_id,record_type);create index if not exists ssl_expiry on public.ssl_certificates(workspace_id,expires_at);create index if not exists email_domain on public.email_services(domain_id);
do $$declare t text;begin foreach t in array array['dns_records','ssl_certificates','email_services'] loop execute format('drop trigger if exists set_updated_at on public.%I',t);execute format('create trigger set_updated_at before update on public.%I for each row execute function public.set_updated_at()',t);execute format('grant select,insert,update,delete on public.%I to authenticated',t);execute format('revoke all on public.%I from anon',t);execute format('alter table public.%I enable row level security',t);execute format('create policy %I on public.%I for select to authenticated using((select private.is_workspace_member(workspace_id)))',t||'_select',t);execute format('create policy %I on public.%I for insert to authenticated with check((select private.is_workspace_member(workspace_id,array[''owner'',''admin'',''member'']::public.workspace_role[])))',t||'_insert',t);execute format('create policy %I on public.%I for update to authenticated using((select private.is_workspace_member(workspace_id,array[''owner'',''admin'',''member'']::public.workspace_role[]))) with check((select private.is_workspace_member(workspace_id,array[''owner'',''admin'',''member'']::public.workspace_role[])))',t||'_update',t);execute format('create policy %I on public.%I for delete to authenticated using((select private.is_workspace_member(workspace_id,array[''owner'',''admin'']::public.workspace_role[])))',t||'_delete',t);end loop;end$$;
commit;
